const origin = String($env.EVENTZEKA_API_ORIGIN || '').replace(/\/+$/, '');
const cronSecret = String($env.EVENTZEKA_CRON_SECRET || '');
const graphBase = String($env.EVENTZEKA_IG_GRAPH_BASE_URL || 'https://graph.instagram.com').replace(/\/+$/, '');
const graphVersion = String($env.EVENTZEKA_IG_GRAPH_VERSION || 'v25.0').replace(/^\/+|\/+$/g, '');
const igUserId = String($env.EVENTZEKA_IG_USER_ID || '');
const accessToken = String($env.EVENTZEKA_IG_ACCESS_TOKEN || '');

if (!origin || !cronSecret) {
  throw new Error('Event Zeka API origin or cron secret is not configured.');
}

const payloadResponse = await fetch(`${origin}/api/social/daily-carousel`, {
  headers: { Authorization: `Bearer ${cronSecret}`, Accept: 'application/json' },
});
const payloadText = await payloadResponse.text();
let payload;
try {
  payload = JSON.parse(payloadText);
} catch {
  throw new Error(`Carousel generator returned non-JSON HTTP ${payloadResponse.status}.`);
}
if (!payloadResponse.ok) {
  throw new Error(`Carousel generator failed: ${payload.error || `HTTP ${payloadResponse.status}`}`);
}
if (!payload.selectedCount || !Array.isArray(payload.slides) || payload.slides.length < 2) {
  return [{ json: { status: 'skipped_no_events', publishDate: payload.publishDate, selectedCount: payload.selectedCount || 0 } }];
}

const state = $getWorkflowStaticData('global');
if (state.lastSelectionKey === payload.selectionKey) {
  return [{ json: { status: 'skipped_already_published', publishDate: payload.publishDate, selectionKey: payload.selectionKey, postId: state.lastPostId || null } }];
}

if (!igUserId || !accessToken) {
  return [{ json: {
    status: 'blocked_meta_authorization_required',
    publishDate: payload.publishDate,
    selectionKey: payload.selectionKey,
    selectedCount: payload.selectedCount,
    slideCount: payload.slides.length,
    venues: payload.slides.filter((slide) => slide.kind === 'event').map((slide) => `@${slide.username}`),
    previewUrls: payload.slides.map((slide) => slide.imageUrl),
  } }];
}

const wait = (milliseconds) => new Promise((resolve) => setTimeout(resolve, milliseconds));
const graphUrl = (path) => [graphBase, graphVersion, path.replace(/^\/+/, '')].filter(Boolean).join('/');

async function readResponse(response) {
  const text = await response.text();
  try { return text ? JSON.parse(text) : {}; } catch { return { raw: text.slice(0, 500) }; }
}

async function graphRequest(path, options = {}) {
  let lastError;
  for (let attempt = 1; attempt <= 3; attempt += 1) {
    const body = options.body ? new URLSearchParams(options.body) : undefined;
    const response = await fetch(graphUrl(path), {
      method: options.method || 'GET',
      headers: {
        Authorization: `Bearer ${accessToken}`,
        Accept: 'application/json',
        ...(body ? { 'Content-Type': 'application/x-www-form-urlencoded' } : {}),
      },
      body,
    });
    const data = await readResponse(response);
    if (response.ok) return data;
    const message = data?.error?.message || data?.error?.error_user_msg || `HTTP ${response.status}`;
    lastError = new Error(`Instagram Graph request failed for ${path}: ${message}`);
    if (response.status !== 429 && response.status < 500) throw lastError;
    await wait(attempt * 3000);
  }
  throw lastError;
}

async function waitForContainer(containerId) {
  for (let attempt = 1; attempt <= 18; attempt += 1) {
    const status = await graphRequest(`${containerId}?fields=status_code,status`);
    if (status.status_code === 'FINISHED') return status;
    if (status.status_code === 'ERROR' || status.status_code === 'EXPIRED') {
      throw new Error(`Instagram media container ${containerId} ended with ${status.status_code}.`);
    }
    await wait(5000);
  }
  throw new Error(`Instagram media container ${containerId} did not finish within 90 seconds.`);
}

const childIds = [];
const fallbackMentionTags = [];
for (const slide of payload.slides) {
  const body = { image_url: slide.imageUrl, is_carousel_item: 'true' };
  if (slide.kind === 'event' && Array.isArray(slide.userTags) && slide.userTags.length) {
    body.user_tags = JSON.stringify(slide.userTags);
  }
  let child;
  try {
    child = await graphRequest(`${igUserId}/media`, { method: 'POST', body });
  } catch (error) {
    if (!body.user_tags) throw error;
    delete body.user_tags;
    fallbackMentionTags.push(slide.username);
    child = await graphRequest(`${igUserId}/media`, { method: 'POST', body });
  }
  if (!child.id) throw new Error('Instagram did not return a child media container ID.');
  await waitForContainer(child.id);
  childIds.push(child.id);
}

const carousel = await graphRequest(`${igUserId}/media`, {
  method: 'POST',
  body: {
    media_type: 'CAROUSEL',
    children: childIds.join(','),
    caption: payload.caption,
  },
});
if (!carousel.id) throw new Error('Instagram did not return a carousel container ID.');
await waitForContainer(carousel.id);
const published = await graphRequest(`${igUserId}/media_publish`, {
  method: 'POST',
  body: { creation_id: carousel.id },
});
if (!published.id) throw new Error('Instagram did not return a published media ID.');

state.lastSelectionKey = payload.selectionKey;
state.lastPublishDate = payload.publishDate;
state.lastPostId = published.id;
state.lastPublishedAt = new Date().toISOString();

return [{ json: {
  status: 'published',
  publishDate: payload.publishDate,
  selectionKey: payload.selectionKey,
  postId: published.id,
  selectedCount: payload.selectedCount,
  slideCount: payload.slides.length,
  fallbackMentionTags,
} }];
